import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Check if input length is within bounds
        if (name.length() > 10) {
            System.out.println("Input too long. Please enter a shorter name.");
            return;
        }

        // Copy input to buffer safely
        char[] buffer = new char[name.length()];
        name.getChars(0, name.length(), buffer, 0);

        System.out.println("Welcome, " + new String(buffer));
    }
}

